{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"mount_file_id":"1-fSbKhnPr0pe9hCEqGG4evOVg1Boeo4M","authorship_tag":"ABX9TyM+JovOdBOlIZtlvmufm+yd"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["# Cell 1: Cài đặt thư viện\n","!pip install -q streamlit ultralytics opencv-python-headless pillow numpy pyngrok"],"metadata":{"collapsed":true,"id":"HxsVNNKrsYIU","executionInfo":{"status":"ok","timestamp":1782698082411,"user_tz":-420,"elapsed":7324,"user":{"displayName":"Nguyen Dinhthanh","userId":"10447822945849573504"}}},"execution_count":10,"outputs":[]},{"cell_type":"code","execution_count":13,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"jjBMP6T7QoyM","executionInfo":{"status":"ok","timestamp":1782698745491,"user_tz":-420,"elapsed":15,"user":{"displayName":"Nguyen Dinhthanh","userId":"10447822945849573504"}},"outputId":"89bdf48f-5786-4997-f7f3-d328947010d8"},"outputs":[{"output_type":"stream","name":"stdout","text":["Overwriting app.py\n"]}],"source":["%%writefile app.py\n","import streamlit as st\n","from PIL import Image\n","import numpy as np\n","from ultralytics import YOLO\n","\n","# ---------------------------------------------------------\n","# Cấu hình giao diện trang web\n","# ---------------------------------------------------------\n","st.set_page_config(page_title=\"Hệ Thống Kiểm Tra Container\", page_icon=\"🚢\", layout=\"centered\")\n","\n","st.title(\"🚢 Container Damage Detection App\")\n","st.write(\"Vui lòng tải lên hình ảnh Container để hệ thống AI tự động kiểm tra các vết lõm, lỗ hổng hoặc rỉ sét.\")\n","\n","# ---------------------------------------------------------\n","# Load Model (Sử dụng cache để web không bị đơ khi load lại)\n","# ---------------------------------------------------------\n","@st.cache_resource\n","def load_model():\n","    # Trỏ thẳng tới file ONNX trên Google Drive của bạn\n","    model_path = '/content/drive/MyDrive/YOLO_Container_Project_TransferLearning/App/best.onnx'\n","    return YOLO(model_path)\n","\n","# Khởi tạo mô hình\n","try:\n","    model = load_model()\n","except Exception as e:\n","    st.error(f\"Không thể tải mô hình. Vui lòng kiểm tra lại đường dẫn file best.onnx. Chi tiết lỗi: {e}\")\n","    st.stop()\n","\n","# ---------------------------------------------------------\n","# Xử lý Upload Ảnh\n","# ---------------------------------------------------------\n","uploaded_file = st.file_uploader(\"Tải ảnh Container lên tại đây...\", type=['jpg', 'jpeg', 'png'])\n","\n","if uploaded_file is not None:\n","    # Mở và hiển thị ảnh gốc\n","    image = Image.open(uploaded_file)\n","    st.image(image, caption='📸 Ảnh gốc', use_container_width=True)\n","\n","    # Chuyển đổi ảnh sang định dạng mảng numpy để đưa vào mô hình YOLO\n","    image_np = np.array(image)\n","\n","    # Nút bấm kích hoạt AI\n","    if st.button(\"🔍 Kiểm Tra Hư Hỏng\", type=\"primary\"):\n","        with st.spinner('Đang phân tích hình ảnh...'):\n","\n","            # Chạy mô hình để nhận diện\n","            results = model.predict(image_np, conf=0.25) # conf=0.25: Bỏ qua các dự đoán có độ tự tin dưới 25%\n","\n","            # Vẽ Bounding Box (khung đỏ) lên ảnh\n","            annotated_image = results[0].plot()\n","\n","            # Hiển thị ảnh sau khi đã nhận diện (Ultralytics plot trả về ảnh BGR nên cần set channels=\"BGR\")\n","            st.image(annotated_image, channels=\"BGR\", caption='🎯 Kết quả nhận diện', use_container_width=True)\n","\n","            # Lấy danh sách các ID class mà AI đã phát hiện được trong bức ảnh\n","            detected_classes_ids = set([int(box.cls) for box in results[0].boxes])\n","            detected_classes_names = [model.names[cls_id] for cls_id in detected_classes_ids]\n","\n","            # ---------------------------------------------------------\n","            # Xuất Thông Báo Theo Yêu Cầu\n","            # ---------------------------------------------------------\n","            st.subheader(\"📋 Báo Cáo Tình Trạng:\")\n","\n","            if len(detected_classes_names) == 0:\n","                st.success(\"✅ Container đạt chuẩn. Không phát hiện hư hỏng nào.\")\n","            else:\n","                # Kiểm tra và in ra thông báo tương ứng với từng loại lỗi\n","                if 'dent' in detected_classes_names:\n","                    st.warning(\"⚠️ Container có vết lõm.\")\n","\n","                if 'hole' in detected_classes_names:\n","                    st.error(\"🚨 Container có lỗ hổng.\")\n","\n","                if 'rust' in detected_classes_names:\n","                    st.info(\"🟠 Container có vết rỉ sét.\")"]},{"cell_type":"code","source":["from google.colab import output\n","import subprocess, time, socket\n","\n","# Tắt tiến trình Streamlit cũ (nếu có)\n","!kill -9 $(lsof -t -i:8501) 2>/dev/null\n","\n","# Chạy Streamlit ngầm với đầy đủ flag cho Colab\n","proc = subprocess.Popen([\n","    'streamlit', 'run', 'app.py',\n","    '--server.port', '8501',\n","    '--server.headless', 'true',\n","    '--server.enableCORS', 'false',\n","    '--server.enableXsrfProtection', 'false',\n","    '--browser.gatherUsageStats', 'false',\n","])\n","\n","# Đợi cho đến khi Streamlit sẵn sàng\n","def wait_for_port(port, timeout=30):\n","    start = time.time()\n","    while time.time() - start < timeout:\n","        try:\n","            with socket.create_connection(('localhost', port), timeout=1):\n","                return True\n","        except OSError:\n","            time.sleep(1)\n","    return False\n","\n","if wait_for_port(8501):\n","    print('✅ Streamlit đã sẵn sàng!')\n","else:\n","    print('❌ Streamlit chưa khởi động được.')\n","\n","# Nhúng iframe\n","output.serve_kernel_port_as_iframe(8501, height=750)"],"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":789},"id":"q540KT9duBF-","executionInfo":{"status":"ok","timestamp":1782698760709,"user_tz":-420,"elapsed":3224,"user":{"displayName":"Nguyen Dinhthanh","userId":"10447822945849573504"}},"outputId":"25ce805b-a40c-4c0f-e6e0-ec508a2ce6f6"},"execution_count":14,"outputs":[{"output_type":"stream","name":"stdout","text":["✅ Streamlit đã sẵn sàng!\n"]},{"output_type":"display_data","data":{"text/plain":["<IPython.core.display.Javascript object>"],"application/javascript":["(async (port, path, width, height, cache, element) => {\n","    if (!google.colab.kernel.accessAllowed && !cache) {\n","      return;\n","    }\n","    element.appendChild(document.createTextNode(''));\n","    const url = await google.colab.kernel.proxyPort(port, {cache});\n","    const iframe = document.createElement('iframe');\n","    iframe.src = new URL(path, url).toString();\n","    iframe.height = height;\n","    iframe.width = width;\n","    iframe.style.border = 0;\n","    iframe.allow = [\n","        'accelerometer',\n","        'autoplay',\n","        'camera',\n","        'clipboard-read',\n","        'clipboard-write',\n","        'gyroscope',\n","        'magnetometer',\n","        'microphone',\n","        'serial',\n","        'usb',\n","        'xr-spatial-tracking',\n","    ].join('; ');\n","    element.appendChild(iframe);\n","  })(8501, \"/\", \"100%\", 750, false, window.element)"]},"metadata":{}}]}]}